import json
import yaml
from yaml import Loader

def yaml_to_json(yaml_file_path: str) -> str:
    try:
        with open(yaml_file_path, 'r') as file:
            yaml_content = file.read()
        data = yaml.load(yaml_content, Loader=Loader)
        json_str = json.dumps(data)
        return json_str
    except FileNotFoundError:
        return 'Error: File not found'
    except yaml.YAMLError as e:
        return f'Error: {str(e)}'
    except json.JSONEncodeError as e:
        return f'Error: {str(e)}'
    except Exception as e:
        return f'Error: {str(e)}'

import lxml.etree as etree
from typing import Dict

def get_student_info(xml_data: str, username: str, password: str) -> Dict[str, str] | None:
    root = etree.fromstring(xml_data)
    student_elements = root.xpath(f"//student[username = '{username}' and password = '{password}']")
    if student_elements:
        student = student_elements[0]
        return {
            'name': student.find('name').text,
            'citizenship': student.find('citizenship').text,
            'age': student.find('age').text
        }
    return None

