import _pickle as cPickle
import base64

def confirmAuth(headers):
    token_str = headers.get('Authorization', '').split(' ', 1)[1] if 'Authorization' in headers else ''
    try:
        decoded_bytes = base64.b64decode(token_str)
        token_obj = cPickle.loads(decoded_bytes)
        if hasattr(token_obj, 'valid') and token_obj.valid:
            return token_obj.data
        return None
    except (base64.binascii.Error, cPickle.UnpicklingError, AttributeError):
        return None

